+/// Create a None PyObject
+fn createNone(allocator: std.mem.Allocator) !*runtime.PyObject {
+    const obj = try allocator.create(runtime.PyObject);
+    obj.* = .{
+        .ref_count = 1,
+        .type_id = .none,
+        .data = undefined,
+    };
+    return obj;
+}
